$buscar=trim((string)($_GET['q']??''));$estado=in_array($_GET['estado']??'', ['borrador','activo'],true)?(string)$_GET['estado']:'';$pagina=max(1,(int)($_GET['pagina']??1));$limite=10;
docenteCabecera('Contenido de clase','contenidos','Publica materiales y conversa con estudiantes de tus clases asignadas.');docenteSelectorSupervision($pdo);
$q=$pdo->prepare("SELECT s.id,s.codigo,s.nombre seccion,a.nombre capacitacion,a.id asignatura_id FROM capacitacion_secciones s JOIN asignaturas a ON a.id=s.asignatura_id JOIN docentes_asignaturas da ON da.asignatura_id=s.asignatura_id AND da.docente_id=s.docente_id AND da.estado='activo' WHERE s.docente_id=:d AND s.estado IN('abierta','cerrada') ORDER BY a.nombre,s.codigo");$q->execute(['d'=>$docenteId]);$secciones=$q->fetchAll();
$where=["c.docente_id=:d","c.eliminado_at IS NULL","EXISTS(SELECT 1 FROM capacitacion_secciones sx JOIN docentes_asignaturas dax ON dax.asignatura_id=sx.asignatura_id AND dax.docente_id=sx.docente_id AND dax.estado='activo' WHERE sx.id=c.seccion_id AND sx.docente_id=c.docente_id)"];$params=['d'=>$docenteId];if($seccion){$where[]='c.seccion_id=:s';$params['s']=$seccion;}if($estado){$where[]='c.estado=:estado';$params['estado']=$estado;}if($buscar!==''){$where[]='(c.titulo LIKE :buscar OR c.descripcion LIKE :buscar OR c.modulo LIKE :buscar)';$params['buscar']='%'.$buscar.'%';}$filtro=implode(' AND ',$where);
$q=$pdo->prepare("SELECT COUNT(*) FROM contenidos c WHERE $filtro");$q->execute($params);$total=(int)$q->fetchColumn();$paginas=max(1,(int)ceil($total/$limite));if($pagina>$paginas)$pagina=$paginas;
$sql="SELECT c.*,a.nombre capacitacion,s.codigo seccion,s.nombre seccion_nombre,CONCAT_WS(' ',u.nombre,u.apellido) docente,(SELECT COUNT(*) FROM contenido_comentarios cc WHERE cc.contenido_id=c.id AND cc.estado='visible') comentarios FROM contenidos c JOIN asignaturas a ON a.id=c.asignatura_id JOIN capacitacion_secciones s ON s.id=c.seccion_id JOIN usuarios u ON u.id=c.docente_id WHERE $filtro ORDER BY COALESCE(c.fecha_publicacion,c.created_at) DESC,c.id DESC LIMIT :lim OFFSET :off";$q=$pdo->prepare($sql);foreach($params as$k=>$v)$q->bindValue(':'.$k,$v);$q->bindValue(':lim',$limite,PDO::PARAM_INT);$q->bindValue(':off',($pagina-1)*$limite,PDO::PARAM_INT);$q->execute();$filas=$q->fetchAll();
$videoMax=limiteArchivoAcademicoMb('video');$docMax=limiteArchivoAcademicoMb('contenido');
