 data-atenea-confirm-text="Sí, eliminar"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$c['id']?>"><input type="hidden" name="accion" value="eliminar"><button class="dropdown-item text-danger" data-atenea-confirm="danger">Eliminar</button></form></div></div></div><?php if($c['descripcion']):?><p class="mt-3 mb-3"><?=nl2br(atenea_e(mb_strimwidth((string)$c['descripcion'],0,700,'…')))?></p><?php endif;?><div class="mb-3"><?php renderizarRecursoContenidoClase($c);?></div><div class="border-top pt-3 d-flex justify-content-between align-items-center"><span class="text-muted"><i class="mdi mdi-comment-outline me-1"></i><?=(int)$c['comentarios']?> comentarios</span><a class="btn btn-sm btn-outline-primary" href="<?=docenteUrl('contenido-vista.php',['id'=>$c['id']])?>">Abrir publicación</a></div></div></article><?php endforeach;?>
